import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import {
  Button,
  Input,
  Modal,
  Select,
  SearchTextInput,
  dispatchAppToast,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { HrEmployeeGroupDto } from '../../../services/ns/models';
import { nhomNhanVienPageLabels as labels } from '../../../constants/nhomNhanVienPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import {
  getErpListRowMenuHint,
  catalogListRowMenuHintDismissStorageKey,
} from '../../../utils/catalogListRowMenuHint';
import { useCatalogListPermissions } from '../../../hooks/useCatalogListPermissions';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useEmployeeGroupFormFields } from '../../../hooks/useEmployeeGroupFormFields';
import {
  HrEmployeeGroupParentLookupField,
  computeChildSlot,
} from '../../../components/ns/employee/HrEmployeeGroupParentLookupField';
import {
  flattenEmployeeGroupTree,
  employeeGroupRowDepth,
  employeeGroupRowCellStyle,
  EMPLOYEE_GROUP_INDENT_PX,
} from '../../../utils/employeeGroupTree';
import {
  CatalogListMasterLinPageLayout,
  CatalogRowActionMenu,
  useCatalogListPaging,
  useCatalogPagination,
  useServerPagedListLoading,
  type CatalogBatchDeleteMode,
  type CatalogListToolbarBridge,
  type CatalogRowMenuAction,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
} from '../../../components/catalog/catalogUiSchema';
import { hrCatalogDocumentTypes } from '../../../config/documentHistoryClients';
import {
  filterCatalogListRows,
  applyCatalogColumnFilters,
  applyCatalogColumnSort,
  catalogCellDisplayTextForKey,
} from '../../../utils/catalogListClientSearch';
import type { ErpListSortState } from '../../../components/catalog/catalogUiSchema/CatalogListGridFromSchema';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-nhom-nhan-vien';
const PAGE_ID = 'ns-nhom-nhan-vien';
const CATALOG_KIND = 'hr-employee-groups';

const emptyGroup = {
  code: '',
  name: '',
  parentId: '',
  parentCode: '',
  parentName: '',
  slot: 1,
  isActive: true,
};

type ModalMode = 'create' | 'edit' | 'view';

const ACTIVE_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: 'true', label: 'Hoạt động' },
  { value: 'false', label: 'Tắt' },
];

const ACTIVE_FORM_OPTIONS = [
  { value: 'true', label: 'Hoạt động' },
  { value: 'false', label: 'Tắt' },
];

const NhomNhanVienPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const viewMobile = useViewMobileLayout();
  const { canWrite } = useCatalogListPermissions(CATALOG_KIND);
  const { fields: groupSlotFields } = useEmployeeGroupFormFields();
  const toolbarBridgeRef = useRef<CatalogListToolbarBridge | null>(null);
  const [reloadKey, setReloadKey] = useState(0);
  const [items, setItems] = useState<HrEmployeeGroupDto[]>([]);
  const [serverTotalCount, setServerTotalCount] = useState(0);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [slotFilter, setSlotFilter] = useState('');
  const [activeFilter, setActiveFilter] = useState('');
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: HrEmployeeGroupDto } | null>(
    null,
  );
  const [modalOpen, setModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('create');
  const [editing, setEditing] = useState<HrEmployeeGroupDto | null>(null);
  const [form, setForm] = useState(emptyGroup);
  const [saving, setSaving] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);
  const [columnFilters, setColumnFilters] = useState<Record<string, string[]>>({});
  const [sortState, setSortState] = useState<ErpListSortState>(null);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);

  const isTreeMode = search.trim().length === 0 && !slotFilter && activeFilter === '';

  const locallyFilteredItems = useMemo(
    () =>
      filterCatalogListRows(
        items as HrEmployeeGroupDto[],
        searchDraft,
        listColumns,
        row => {
          const slotLabel = groupSlotFields.find(f => f.slot === row.slot)?.label;
          return slotLabel ? [slotLabel] : [];
        },
      ),
    [items, searchDraft, listColumns, groupSlotFields],
  );

  const columnFilteredItems = useMemo(
    () => applyCatalogColumnFilters(
      locallyFilteredItems as Record<string, unknown>[],
      listColumns,
      columnFilters,
    ) as HrEmployeeGroupDto[],
    [locallyFilteredItems, listColumns, columnFilters],
  );

  const sortedItems = useMemo(
    () => applyCatalogColumnSort(
      columnFilteredItems as Record<string, unknown>[],
      listColumns,
      sortState,
    ) as HrEmployeeGroupDto[],
    [columnFilteredItems, listColumns, sortState],
  );

  const {
    page: serverPage,
    setPage: setServerPage,
    pageSize: serverPageSize,
    setPageSize: setServerPageSize,
    resetPage: resetServerPage,
  } = useCatalogListPaging();
  const {
    showTableLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const displayRows = useMemo(
    () => (isTreeMode ? flattenEmployeeGroupTree(sortedItems) : sortedItems),
    [sortedItems, isTreeMode],
  );
  const clientPaging = useCatalogPagination(displayRows);

  const page = isTreeMode ? clientPaging.page : serverPage;
  const setPage = isTreeMode ? clientPaging.setPage : setServerPage;
  const pageSize = isTreeMode ? clientPaging.pageSize : serverPageSize;
  const setPageSize = isTreeMode ? clientPaging.setPageSize : setServerPageSize;
  const totalCount = isTreeMode ? clientPaging.totalCount : serverTotalCount;
  const tableRows = isTreeMode ? clientPaging.pageItems : sortedItems;
  const batchSource = isTreeMode ? displayRows : sortedItems;
  const filterSourceRows = locallyFilteredItems;

  const resetPage = useCallback(() => {
    resetServerPage();
    clientPaging.resetPage();
  }, [clientPaging, resetServerPage]);

  const slotFilterOptions = useMemo(
    () => [
      { value: '', label: labels.slotAll },
      ...groupSlotFields.map(f => ({ value: String(f.slot), label: f.label })),
    ],
    [groupSlotFields],
  );

  const slotDisplayLabel = useMemo(() => {
    const match = groupSlotFields.find(f => f.slot === form.slot);
    return match?.label ?? `${labels.slotLabel} ${form.slot}`;
  }, [form.slot, groupSlotFields]);

  const slotSelectOptions = useMemo(
    () => groupSlotFields.map(f => ({ value: String(f.slot), label: f.label })),
    [groupSlotFields],
  );

  const slotLockedByParent = modalMode === 'create' && !!form.parentId;

  const selection = useCatalogListSelection({
    rows: tableRows,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = useCallback(() => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection, setLoadingMode]);

  const commitSearch = useCallback(
    (nextSearch?: string) => {
      const q = (nextSearch ?? searchDraft).trim();
      pulseSearch(() => {
        setLoadingMode('filter');
        setSearch(q);
        resetPage();
        selection.clearSelection();
      });
    },
    [pulseSearch, resetPage, searchDraft, selection, setLoadingMode],
  );

  const handleSearch = useCallback(() => {
    commitSearch();
  }, [commitSearch]);

  const handleSearchDraftChange = useCallback(
    (value: string) => {
      setSearchDraft(value);
      if (value.trim().length === 0 && search.trim().length > 0) {
        commitSearch('');
        return;
      }
      if (search.trim().length === 0 && !slotFilter && activeFilter === '') {
        clientPaging.resetPage();
      }
      selection.clearSelection();
    },
    [activeFilter, clientPaging, commitSearch, search, selection, slotFilter],
  );

  const getColumnDisplayValue = useCallback(
    (row: HrEmployeeGroupDto, columnKey: string) => {
      if (columnKey === 'slot') {
        const slotLabel = groupSlotFields.find(f => f.slot === row.slot)?.label;
        if (slotLabel) return slotLabel;
      }
      return catalogCellDisplayTextForKey(
        row as unknown as Record<string, unknown>,
        listColumns,
        columnKey,
      );
    },
    [groupSlotFields, listColumns],
  );

  const handleColumnFilterConfirm = useCallback(
    (columnKey: string, selectedValues: string[]) => {
      setColumnFilters(prev => ({ ...prev, [columnKey]: selectedValues }));
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const handleColumnFilterClear = useCallback(
    (columnKey: string) => {
      setColumnFilters(prev => {
        const next = { ...prev };
        delete next[columnKey];
        return next;
      });
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const handleSortChange = useCallback(
    (sort: ErpListSortState) => {
      setSortState(sort);
      resetPage();
      selection.clearSelection();
    },
    [resetPage, selection],
  );

  const openModal = useCallback((mode: ModalMode, row?: HrEmployeeGroupDto, parent?: HrEmployeeGroupDto) => {
    setModalMode(mode);
    setEditing(row ?? null);
    setDeleteConfirm(false);
    if (row) {
      setForm({
        code: row.code,
        name: row.name,
        parentId: row.parentId ?? '',
        parentCode: row.parentCode ?? '',
        parentName: row.parentName ?? '',
        slot: row.slot,
        isActive: row.isActive,
      });
    } else if (parent) {
      setForm({
        ...emptyGroup,
        parentId: parent.id,
        parentCode: parent.code,
        parentName: parent.name,
        slot: computeChildSlot(parent.slot),
      });
    } else {
      setForm({ ...emptyGroup, slot: groupSlotFields[0]?.slot ?? 1 });
    }
    setModalOpen(true);
  }, [groupSlotFields]);

  const openView = useCallback((row: HrEmployeeGroupDto) => openModal('view', row), [openModal]);

  const openEdit = useCallback(
    (row: HrEmployeeGroupDto) => {
      if (!canWrite) {
        openView(row);
        return;
      }
      openModal('edit', row);
    },
    [canWrite, openModal, openView],
  );

  useEffect(() => {
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      hrService
        .getEmployeeGroups({
          search: search || undefined,
          slot: slotFilter ? Number(slotFilter) : undefined,
          isActive: activeFilter === '' ? undefined : activeFilter === 'true',
          page: isTreeMode ? 1 : serverPage,
          pageSize: isTreeMode ? 500 : serverPageSize,
        })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setServerTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) endFetch();
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [
    dispatch,
    search,
    slotFilter,
    activeFilter,
    isTreeMode,
    serverPage,
    serverPageSize,
    reloadKey,
    beginFetch,
    endFetch,
  ]);

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: HrEmployeeGroupDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: CatalogRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          openView(row);
          break;
        case 'edit':
          openEdit(row);
          break;
        case 'history':
          toolbarBridgeRef.current?.openHistory();
          break;
        case 'delete':
          if (!selection.isRowChecked(row)) {
            selection.toggleRow(row, true);
          }
          toolbarBridgeRef.current?.openDelete();
          break;
        default:
          break;
      }
    },
    [rowMenu?.row, openEdit, openView, selection],
  );

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? batchSource.map(r => r.id)
        : [...selection.selectedIds];
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(
        ids.map(id => {
          const row = batchSource.find(r => r.id === id)!;
          return hrService.updateEmployeeGroup(id, { name: row.name, isActive: false });
        }),
      );
      dispatchAppToast(dispatch, {
        message: `Đã tắt ${ids.length} nhóm nhân viên`,
        type: 'success',
      });
    } else {
      await Promise.all(ids.map(id => hrService.deleteEmployeeGroup(id)));
      dispatchAppToast(dispatch, {
        message: `Đã xóa ${ids.length} nhóm nhân viên`,
        type: 'success',
      });
    }
    refresh();
  };

  const handleSave = async () => {
    if (modalMode === 'view') return;
    if (!form.code.trim() || !form.name.trim()) {
      dispatchAppToast(dispatch, { message: labels.codeNameSlotRequired, type: 'error' });
      return;
    }
    setSaving(true);
    try {
      if (modalMode === 'edit' && editing) {
        await hrService.updateEmployeeGroup(editing.id, {
          name: form.name.trim(),
          isActive: form.isActive,
        });
        dispatchAppToast(dispatch, { message: labels.updateSuccess, type: 'success' });
      } else {
        await hrService.createEmployeeGroup({
          code: form.code.trim().toUpperCase(),
          name: form.name.trim(),
          parentId: form.parentId || undefined,
          slot: form.parentId ? undefined : form.slot,
        });
        dispatchAppToast(dispatch, { message: labels.createSuccess, type: 'success' });
      }
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!editing || !canWrite) return;
    try {
      await hrService.deleteEmployeeGroup(editing.id);
      dispatchAppToast(dispatch, { message: labels.deleteSuccess, type: 'success' });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.deleteError),
        type: 'error',
      });
    }
  };

  const readOnly = modalMode === 'view';
  const modalTitle =
    modalMode === 'create'
      ? labels.modalAddTitle
      : modalMode === 'edit'
        ? labels.modalEditTitle
        : labels.modalViewTitle;

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = !!rowMenuRow && canWrite;
  const rowMenuShowView = !!rowMenuRow && !canWrite;
  const rowMenuHintMessage = getErpListRowMenuHint(viewMobile);

  const gridPendingSchema = displayRows.length > 0 && listColumns.length === 0;

  const filterBar = (
    <>
      <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder={labels.searchPlaceholder}
          value={searchDraft}
          onChange={handleSearchDraftChange}
          onSearch={handleSearch}
          testId={`${TEST_ID}-search-text`}
        />
      </div>
      <div className={styles.field} data-testid={`${TEST_ID}-field-slot`}>
        <Select
          label={labels.slotLabel}
          value={slotFilter}
          onChange={e => {
            setLoadingMode('filter');
            setSlotFilter(e.target.value);
            resetPage();
            selection.clearSelection();
            setReloadKey(k => k + 1);
          }}
          options={slotFilterOptions}
          fullWidth
        />
      </div>
      <div className={styles.field} data-testid={`${TEST_ID}-field-active`}>
        <Select
          label="Trạng thái"
          value={activeFilter}
          onChange={e => {
            setLoadingMode('filter');
            setActiveFilter(e.target.value);
            resetPage();
            selection.clearSelection();
            setReloadKey(k => k + 1);
          }}
          options={ACTIVE_OPTIONS}
          fullWidth
        />
      </div>
    </>
  );

  return (
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        catalogKind={CATALOG_KIND}
        documentType={hrCatalogDocumentTypes[CATALOG_KIND]}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={tableRows}
        onAdd={() => openModal('create')}
        onEdit={openEdit}
        onRefresh={refresh}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        toolbarBridgeRef={toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => {
          setLoadingMode('page');
          setPage(p);
          selection.clearSelection();
        }}
        onPageSizeChange={size => {
          setLoadingMode('filter');
          setPageSize(size);
        }}
        showTableLoading={showTableLoading}
        header={{
          title: labels.listTitle,
          titleIconClass: 'fas fa-layer-group',
          pageId: PAGE_ID,
        }}
        listTitle={labels.listSubtitle}
        listRowMenuHelp
        filters={filterBar}
        filterMaxWidthPx={1000}
        schemaEditorModal={
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => reloadSchema()}
          />
        }
        extraModals={
          <CatalogRowActionMenu
            open={rowMenu != null}
            x={rowMenu?.x ?? 0}
            y={rowMenu?.y ?? 0}
            onClose={() => setRowMenu(null)}
            onSelect={handleRowMenuSelect}
            testIdPrefix={TEST_ID}
            showEdit={rowMenuShowEdit}
            showView={rowMenuShowView}
            showHistory={!!rowMenuRow}
            showDelete={rowMenuShowEdit}
          />
        }
      >
        {displayRows.length === 0 && !showTableLoading ? (
          <div className={styles.empty} data-testid={`${TEST_ID}-empty`}>
            <i className="fas fa-inbox" />
            <p>{searchDraft.trim() ? 'Không tìm thấy nhóm phù hợp' : labels.empty}</p>
          </div>
        ) : listColumns.length > 0 && !gridPendingSchema ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={tableRows}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            getTreeRowDepth={isTreeMode ? employeeGroupRowDepth : undefined}
            treeIndentPx={EMPLOYEE_GROUP_INDENT_PX}
            getRowCellStyle={employeeGroupRowCellStyle}
            filterSourceRows={filterSourceRows}
            getColumnDisplayValue={getColumnDisplayValue}
            columnFilters={columnFilters}
            onColumnFilterConfirm={handleColumnFilterConfirm}
            onColumnFilterClear={handleColumnFilterClear}
            sortState={sortState}
            onSortChange={handleSortChange}
            onRowOpenActionMenu={handleRowOpenActionMenu}
            rowMenuHintMessage={rowMenuHintMessage}
            rowMenuHintDismissStorageKey={catalogListRowMenuHintDismissStorageKey(TEST_ID)}
            enableRowMenuLongPress={viewMobile}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={modalTitle}>
        <div className={styles.modalBody}>
          <div className={styles.field}>
            <label className={styles.label}>Mã nhóm *</label>
            <Input
              value={form.code}
              onChange={e => setForm(f => ({ ...f, code: e.target.value.toUpperCase() }))}
              disabled={readOnly || modalMode !== 'create'}
              data-testid={`${TEST_ID}-field-code`}
            />
          </div>
          <div className={styles.field}>
            <label className={styles.label}>Tên nhóm *</label>
            <Input
              value={form.name}
              onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
              disabled={readOnly}
              data-testid={`${TEST_ID}-field-name`}
            />
          </div>
          <div className={styles.field}>
            <label className={styles.label}>{labels.parentLabel}</label>
            {modalMode === 'create' ? (
              <>
                <HrEmployeeGroupParentLookupField
                  parentId={form.parentId}
                  parentCode={form.parentCode}
                  parentName={form.parentName}
                  disabled={readOnly}
                  onChange={row =>
                    setForm(f => ({
                      ...f,
                      parentId: row.id,
                      parentCode: row.code,
                      parentName: row.name,
                      slot: computeChildSlot(row.slot),
                    }))
                  }
                  onClear={() =>
                    setForm(f => ({
                      ...f,
                      parentId: '',
                      parentCode: '',
                      parentName: '',
                    }))
                  }
                  testId={`${TEST_ID}-field-parent`}
                />
                <span style={{ fontSize: 12, color: 'var(--ds-color-text-tertiary, #6b7280)' }}>
                  {labels.parentHint}
                </span>
              </>
            ) : (
              <Input
                value={
                  form.parentCode && form.parentName
                    ? `${form.parentCode} — ${form.parentName}`
                    : form.parentName || form.parentCode || '—'
                }
                disabled
                readOnly
                data-testid={`${TEST_ID}-field-parent-readonly`}
              />
            )}
          </div>
          <div className={styles.field}>
            {modalMode === 'create' && !form.parentId && !readOnly ? (
              <>
                <Select
                  label={labels.slotLabel}
                  value={String(form.slot)}
                  onChange={e =>
                    setForm(f => ({ ...f, slot: Number(e.target.value) || 1 }))
                  }
                  options={slotSelectOptions}
                  fullWidth
                  data-testid={`${TEST_ID}-field-slot`}
                />
                <span style={{ fontSize: 12, color: 'var(--ds-color-text-tertiary, #6b7280)' }}>
                  {labels.slotManualHint}
                </span>
              </>
            ) : (
              <>
                <label className={styles.label}>{labels.slotLabel}</label>
                <Input
                  value={slotDisplayLabel}
                  disabled
                  readOnly
                  data-testid={`${TEST_ID}-field-slot`}
                />
                {modalMode === 'create' && slotLockedByParent ? (
                  <span style={{ fontSize: 12, color: 'var(--ds-color-text-tertiary, #6b7280)' }}>
                    {labels.slotAutoHint}
                  </span>
                ) : null}
              </>
            )}
          </div>
          {modalMode === 'edit' || modalMode === 'view' ? (
            <div className={styles.field}>
              <Select
                label="Trạng thái"
                value={form.isActive ? 'true' : 'false'}
                onChange={e => setForm(f => ({ ...f, isActive: e.target.value === 'true' }))}
                options={ACTIVE_FORM_OPTIONS}
                fullWidth
                disabled={readOnly}
                data-testid={`${TEST_ID}-field-active`}
              />
            </div>
          ) : null}
          <div className={styles.modalActions}>
            {modalMode === 'edit' && canWrite ? (
              deleteConfirm ? (
                <>
                  <Button
                    variant="danger"
                    onClick={handleDelete}
                    data-testid={`${TEST_ID}-delete-confirm`}
                  >
                    Xác nhận xóa
                  </Button>
                  <Button variant="secondary" onClick={() => setDeleteConfirm(false)}>
                    Huỷ xóa
                  </Button>
                </>
              ) : (
                <Button
                  variant="danger"
                  onClick={() => setDeleteConfirm(true)}
                  data-testid={`${TEST_ID}-delete`}
                >
                  Xóa
                </Button>
              )
            ) : null}
            <span style={{ flex: 1 }} />
            <Button variant="secondary" onClick={() => setModalOpen(false)}>
              {readOnly ? 'Đóng' : 'Huỷ'}
            </Button>
            {!readOnly ? (
              <Button
                variant="primary"
                onClick={handleSave}
                disabled={saving || !canWrite}
                data-testid={`${TEST_ID}-save`}
              >
                {saving ? 'Đang lưu...' : 'Lưu'}
              </Button>
            ) : null}
          </div>
        </div>
      </Modal>
    </>
  );
};

export default NhomNhanVienPage;
