import type { CSSProperties } from 'react';
import type { HrEmployeeGroupDto } from '../services/ns/models';

/** Parity TaiKhoanPage / materialGroupTree — 16px per level. */
export const EMPLOYEE_GROUP_INDENT_PX = 16;

export const MAX_EMPLOYEE_GROUP_SLOT = 4;

/**
 * Flatten employee groups depth-first (parent → children) for tree table display.
 * Siblings sorted by `code`.
 */
export function flattenEmployeeGroupTree(items: HrEmployeeGroupDto[]): HrEmployeeGroupDto[] {
  const childrenOf = new Map<string | null, HrEmployeeGroupDto[]>();
  for (const g of items) {
    const key = g.parentId ?? null;
    const list = childrenOf.get(key);
    if (list) list.push(g);
    else childrenOf.set(key, [g]);
  }
  for (const list of childrenOf.values()) {
    list.sort((a, b) => a.code.localeCompare(b.code, 'vi'));
  }

  const out: HrEmployeeGroupDto[] = [];
  const visit = (parentId: string | null) => {
    for (const g of childrenOf.get(parentId) ?? []) {
      out.push(g);
      visit(g.id);
    }
  };
  visit(null);
  return out;
}

/** Tree depth for indent — slot equals hierarchy level (1..4). */
export function employeeGroupRowDepth(row: HrEmployeeGroupDto): number {
  return Math.max(1, row.slot ?? 1);
}

/** Grid cell style from BE fontColor / backgroundColor. */
export function employeeGroupRowCellStyle(
  row: HrEmployeeGroupDto,
): CSSProperties | undefined {
  if (!row.backgroundColor && !row.fontColor) return undefined;
  return {
    backgroundColor: row.backgroundColor ?? undefined,
    color: row.fontColor ?? undefined,
  };
}

export function employeeGroupRowIndent(depth: number): number {
  return Math.max(0, depth - 1) * EMPLOYEE_GROUP_INDENT_PX;
}
